import React, { useState } from 'react';
import {
  View,
  StyleSheet,
  Modal,
  TextInput,
  TouchableWithoutFeedback,
  Keyboard,
} from 'react-native';
import { Text, Button } from 'tradewize-component';
import { SvgXml } from 'react-native-svg';
import { colors } from '../../../theme';
import { useAppTranslation } from '../../../hooks/useAppTranslation';
import { IconClose } from '../../../assets/svg';

interface SubmitModalProps {
  visible: boolean;
  onClose: () => void;
  onSubmit: (values: {
    dateSchedule: { dateDelivery: string };
    reason: string;
  }) => void;
  deliveryDates: any[];
}

const SubmitModal: React.FC<SubmitModalProps> = ({
  visible,
  onClose,
  onSubmit,
  deliveryDates,
}) => {
  const { t } = useAppTranslation();
  const [selectedDate, setSelectedDate] = useState<any>(null);
  const [reason, setReason] = useState('');

  const handleClose = () => {
    setSelectedDate(null);
    setReason('');
    onClose();
  };

  const handleSubmit = () => {
    if (!selectedDate) {
      // Show error - need to select date
      return;
    }

    onSubmit({
      dateSchedule: selectedDate,
      reason,
    });
    handleClose();
  };

  return (
    <Modal
      visible={visible}
      transparent
      animationType="fade"
      onRequestClose={handleClose}
    >
      <TouchableWithoutFeedback onPress={Keyboard.dismiss}>
        <View style={styles.overlay}>
          <View style={styles.container}>
            {/* Header */}
            <View style={styles.header}>
              <Text style={styles.headerText}>{t('RESCHEDULE')}</Text>
              <Button style={styles.closeButton} onPress={handleClose}>
                <SvgXml xml={IconClose(colors.black)} width={20} height={20} />
              </Button>
            </View>

            {/* Date Selection */}
            <View style={styles.section}>
              <Text style={styles.label}>{t('SELECT_DATE')}</Text>
              <View style={styles.dateList}>
                {deliveryDates.map((date) => (
                  <Button
                    key={date.key}
                    style={[
                      styles.dateButton,
                      selectedDate?.key === date.key && styles.dateButtonSelected,
                    ]}
                    onPress={() => setSelectedDate(date)}
                  >
                    <Text
                      style={[
                        styles.dateText,
                        selectedDate?.key === date.key && styles.dateTextSelected,
                      ]}
                    >
                      {date.value}
                    </Text>
                  </Button>
                ))}
              </View>
            </View>

            {/* Reason Input */}
            <View style={styles.section}>
              <Text style={styles.label}>{t('REASON')}</Text>
              <TextInput
                placeholder={t('ENTER_REASON')}
                placeholderTextColor={colors.grayScale50}
                multiline
                style={styles.reasonInput}
                value={reason}
                onChangeText={setReason}
              />
            </View>

            {/* Submit Button */}
            <Button
              style={[
                styles.submitButton,
                !selectedDate && styles.submitButtonDisabled,
              ]}
              onPress={handleSubmit}
              disabled={!selectedDate}
            >
              <Text style={styles.submitButtonText}>{t('SUBMIT')}</Text>
            </Button>
          </View>
        </View>
      </TouchableWithoutFeedback>
    </Modal>
  );
};

const styles = StyleSheet.create({
  overlay: {
    flex: 1,
    backgroundColor: colors.overlay03,
    justifyContent: 'center',
    alignItems: 'center',
    padding: 16,
  },
  container: {
    backgroundColor: colors.white,
    borderRadius: 16,
    padding: 20,
    width: '100%',
    maxHeight: '80%',
  },
  header: {
    flexDirection: 'row',
    justifyContent: 'space-between',
    alignItems: 'center',
    marginBottom: 20,
  },
  headerText: {
    fontSize: 18,
    fontWeight: '600',
    color: colors.black,
  },
  closeButton: {
    padding: 4,
  },
  section: {
    marginBottom: 16,
  },
  label: {
    fontSize: 14,
    fontWeight: '600',
    color: colors.black,
    marginBottom: 8,
  },
  dateList: {
    gap: 8,
  },
  dateButton: {
    paddingVertical: 12,
    paddingHorizontal: 16,
    borderWidth: 1,
    borderColor: colors.grayScale70,
    borderRadius: 8,
    backgroundColor: colors.white,
  },
  dateButtonSelected: {
    borderColor: colors.mainColorPrimary,
    backgroundColor: colors.mainColorPrimary + '10',
  },
  dateText: {
    fontSize: 14,
    color: colors.black,
  },
  dateTextSelected: {
    color: colors.mainColorPrimary,
    fontWeight: '600',
  },
  reasonInput: {
    borderWidth: 1,
    borderColor: colors.grayScale70,
    borderRadius: 8,
    padding: 12,
    height: 100,
    textAlignVertical: 'top',
    fontSize: 14,
    color: colors.black,
  },
  submitButton: {
    backgroundColor: colors.mainColorPrimary,
    paddingVertical: 14,
    borderRadius: 8,
    alignItems: 'center',
    marginTop: 8,
  },
  submitButtonDisabled: {
    backgroundColor: colors.grayScale70,
  },
  submitButtonText: {
    color: colors.white,
    fontSize: 16,
    fontWeight: '600',
  },
});

export default SubmitModal;
