import React, { useState, useCallback, useEffect } from 'react';
import { createNativeStackNavigator } from '@react-navigation/native-stack';
import MainBottomTabNavigator from './BottomTabNavigator';
import { SCREEN_ENUM } from '../types/global';
import ChangePassword from '../screens/ChangePassword';
import InsuranceBenefitsScreen from '../screens/InsuranceBenefits';
import ReferFriendScreen from '../screens/ReferFriend';
import PaymentMethodScreen from '../screens/PaymentMethod';
import NetworkScreen from '../screens/NetworkScreen';
import ReviewScreen from '../screens/ReviewScreen';
import ReviewHistoryScreen from '../screens/ReviewHistoryScreen';
import UserProfileScreen from '../screens/UserProfile';
import ContractScreen from '../screens/Contract';
import RoleTypeScreen from '../screens/RoleType';
import MyJobsScreen from '../screens/MyJobScreen';
import RegisterCompanyListScreen from '../screens/RegisterCompanyListScreen';
import RegisterCompanyTestScreen from '../screens/RegisterCompanyTestScreen';
import PaymentAccountScreen from '../screens/PaymentInfoW9';
import BankInfoDataScreen from '../screens/BankInfoDataScreen';
import LegalPolicy from '../screens/LegalPolicy';
import LeaderBoard from '../screens/LeaderBoard';
import NotificationScreen from '../screens/NotificationScreen';
import SystemQualityGuideScreen from '../screens/SystemQualityGuide';
import TakeTheTestScreen from '../screens/TakeTheTest';
import FeedbackListScreen from '../screens/FeedbackListScreen';
import FeedbackDetailScreen from '../screens/FeedbackDetailScreen';
import FeedbackAddScreen from '../screens/FeedbackAddScreen';
import MyBudget from '../screens/MyBudget';
import JobBoardScreen from '../screens/JobBoard';
import JobDetailScreen from '../screens/JobDetailScreen';
import MaterialListScreen from '../screens/MaterialListScreen';
import MessageDetailScreen from '../screens/MessageDetail';
import ListMemberJobsBoardScreen from '../screens/ListMemberJobsBoard';
import JobReadyChecklistScreen from '../screens/JobReadyChecklist';
import { ImageBackground, StyleSheet, View } from 'react-native';
import FloatingActionButton from '../components/FloatingActionButton';
import { colors } from '../theme';
import { Button, SCREEN_WIDTH, Text } from 'tradewize-component';
import { improveNoTextBanner } from '../assets/images';
import { useAppTranslation } from '../hooks/useAppTranslation';
import { SvgXml } from 'react-native-svg';
import { IconClose } from '../assets/svg';
import { NavigationService } from '../services/NavigationService';
import { ARR_MAX_Y_FAB, hideFAB, logger } from '../utils';
import { useDispatch, useSelector } from 'react-redux';
import ReferalCompleteJobDetail from '../screens/ReferalCompleteJobDetail';

const MainNavigator = () => {
  const dispatch = useDispatch();
  const { t } = useAppTranslation();
  const Stack = createNativeStackNavigator();

  // State để track FAB visibility
  const [isFabVisible, setIsFabVisible] = useState(true);

  const isMaxY = useSelector((state: any) => state.app.isMaxHeightFAB);
  const tabBarHeight = useSelector((state: any) => state.app.tabBarHeight);

  // Callback khi screen được focus - reset FAB visibility
  const handleScreenFocus = useCallback(async () => {
    try {
      const redux = await import('auth/redux');
      const currentRoute = NavigationService.getCurrentRoute();
      if (ARR_MAX_Y_FAB?.includes(currentRoute as string)) {
        dispatch(redux.actionContainer?.setIsFabVisible(true));
      } else {
        dispatch(redux.actionContainer?.setIsFabVisible(false));
      }
      setIsFabVisible(true);
    } catch (error) {
      logger('handleScreenFocus', error);
    }
  }, []);

  const handlePress = () => {
    NavigationService.navigate(SCREEN_ENUM.FeedbackListScreen);
  };

  const handleClose = () => {
    setIsFabVisible(false);
  };

  return (
    <View style={styles.container}>
      <Stack.Navigator
        screenOptions={{ headerShown: false }}
        screenListeners={{
          focus: handleScreenFocus,
        }}
      >
        <Stack.Screen
          name={SCREEN_ENUM.MainBottomTabNavigator}
          component={MainBottomTabNavigator}
        />
        <Stack.Screen
          name={SCREEN_ENUM.ChangePasswordScreen}
          component={ChangePassword}
        />
        <Stack.Screen
          name={SCREEN_ENUM.InsuranceBenefitsScreen}
          component={InsuranceBenefitsScreen}
        />
        <Stack.Screen
          name={SCREEN_ENUM.ReferFriendScreen}
          component={ReferFriendScreen}
        />
        <Stack.Screen
          name={SCREEN_ENUM.PaymentMethodScreen}
          component={PaymentMethodScreen}
        />
        <Stack.Screen
          name={SCREEN_ENUM.NetworkScreen}
          component={NetworkScreen}
        />
        <Stack.Screen
          name={SCREEN_ENUM.ReviewScreen}
          component={ReviewScreen}
        />
        <Stack.Screen
          name={SCREEN_ENUM.ReviewHistoryScreen}
          component={ReviewHistoryScreen}
        />
        <Stack.Screen
          name={SCREEN_ENUM.UserProfileScreen}
          component={UserProfileScreen}
        />
        <Stack.Screen
          name={SCREEN_ENUM.ChangePasswordMainScreen}
          component={ChangePassword}
        />
        <Stack.Screen
          name={SCREEN_ENUM.ContractScreen}
          component={ContractScreen}
        />
        <Stack.Screen
          name={SCREEN_ENUM.RoleTypeScreen}
          component={RoleTypeScreen}
        />
        <Stack.Screen
          name={SCREEN_ENUM.MyJobsScreen}
          component={MyJobsScreen}
        />

        <Stack.Screen
          name={SCREEN_ENUM.RegisterCompanyListScreen}
          component={RegisterCompanyListScreen}
        />
        <Stack.Screen
          name={SCREEN_ENUM.RegisterCompanyTestScreen}
          component={RegisterCompanyTestScreen}
        />

        <Stack.Screen
          name={SCREEN_ENUM.PaymentAccountScreen}
          component={PaymentAccountScreen}
        />

        <Stack.Screen
          name={SCREEN_ENUM.BankInfoDataScreen}
          component={BankInfoDataScreen}
        />

        <Stack.Screen
          name={SCREEN_ENUM.LegalPolicyScreen}
          component={LegalPolicy}
        />
        <Stack.Screen
          name={SCREEN_ENUM.LeaderBoardScreen}
          component={LeaderBoard}
        />
        <Stack.Screen
          name={SCREEN_ENUM.NotificationScreen}
          component={NotificationScreen}
        />

        <Stack.Screen
          name={SCREEN_ENUM.SystemQualityGuideScreen}
          component={SystemQualityGuideScreen}
        />

        <Stack.Screen
          name={SCREEN_ENUM.TakeTheTestScreen}
          component={TakeTheTestScreen}
        />

        <Stack.Screen
          name={SCREEN_ENUM.FeedbackListScreen}
          component={FeedbackListScreen}
        />

        <Stack.Screen
          name={SCREEN_ENUM.FeedbackDetailScreen}
          component={FeedbackDetailScreen}
        />

        <Stack.Screen
          name={SCREEN_ENUM.FeedbackAddScreen}
          component={FeedbackAddScreen}
        />
        <Stack.Screen name={SCREEN_ENUM.MyBudgetScreen} component={MyBudget} />

        <Stack.Screen
          name={SCREEN_ENUM.JobBoardScreen}
          component={JobBoardScreen}
        />

        <Stack.Screen
          name={SCREEN_ENUM.JobDetailScreen}
          component={JobDetailScreen}
        />

        <Stack.Screen
          name={SCREEN_ENUM.MaterialListScreen}
          component={MaterialListScreen}
        />

        <Stack.Screen
          name={SCREEN_ENUM.MessageDetailScreen}
          component={MessageDetailScreen}
        />

        <Stack.Screen
          name={SCREEN_ENUM.ListMemberJobsBoardScreen}
          component={ListMemberJobsBoardScreen}
        />

        <Stack.Screen
          name={SCREEN_ENUM.ReferalCompleteJobDetailScreen}
          component={ReferalCompleteJobDetail}
        />

        <Stack.Screen
          name={SCREEN_ENUM.JobReadyChecklistScreen}
          component={JobReadyChecklistScreen}
        />
      </Stack.Navigator>

      {isFabVisible &&
        !hideFAB.includes(NavigationService.getCurrentRoute() as string) && (
          <FloatingActionButton
            onPress={handlePress}
            size={SCREEN_WIDTH * 0.15}
            bottomBoundary={isMaxY ? tabBarHeight : 24}
            backgroundColor={colors.mainColorPrimary}
            renderMainContent={() => (
              <ImageBackground
                source={improveNoTextBanner}
                style={styles.imageBackground}
                imageStyle={[styles.imageStyle]}
              >
                <Text style={styles.text}>{t('IMPROVE')}</Text>
                <Button onPress={handleClose} style={styles.button}>
                  <SvgXml
                    xml={IconClose()}
                    width={SCREEN_WIDTH * 0.04}
                    height={SCREEN_WIDTH * 0.04}
                  />
                </Button>
              </ImageBackground>
            )}
          />
        )}
    </View>
  );
};

const styles = StyleSheet.create({
  container: {
    flex: 1,
  },
  imageBackground: {
    width: SCREEN_WIDTH * 0.15,
    height: SCREEN_WIDTH * 0.15,
  },
  imageStyle: {
    borderRadius: SCREEN_WIDTH,
  },
  text: {
    color: colors.white,
    fontSize: 10,
    textAlign: 'center',
    lineHeight: 16,
    marginTop: 8,
    letterSpacing: -0.2,
    fontWeight: 'bold',
  },
  button: {
    position: 'absolute',
    top: -4,
    right: -12,
    minHeight: 0,
    paddingVertical: 2,
    paddingHorizontal: 2,
    borderRadius: SCREEN_WIDTH,
    backgroundColor: 'transparent',
  },
});

export default MainNavigator;
