import React, { useMemo, useState } from 'react';
import { View } from 'react-native';
import { Text, Button } from 'tradewize-component';
import { colors } from '../../../../theme';
import { SvgXml } from 'react-native-svg';
import { IconCheck, IconComment } from '../../../../assets/svg';
import {
  ChecklistItem,
  FileSetting,
  userRole,
  ChecklistMode,
  JobReadyOption,
} from '../../../../types/jobDetail.type';
import { SCREEN_ENUM } from '../../../../types/global';
import { useAppTranslation } from '../../../../hooks/useAppTranslation';
import {
  FileThumbnail,
  FileInfo,
  FileViewer,
} from '../../../../components/FileViewer';
import { dispatch } from '../../../../helper';
import { actionContainer } from '../../../../../../Auth/src/redux';
import {
  isPassValidateFilesByFileSetting,
  isPassValidateJobReady,
  detectChecklistMode,
  JOB_READY_OPTIONS,
} from '../../../../helper/checkList.helpter';
import {
  hideAlertAsync,
  hideConfirmModal,
  showAlertAsync,
  showConfirmModal,
} from '../../../../../../Auth/src/redux/features/app/actions';
import { actionJobDetail } from '../../../../../../Auth/src/redux/features/jobDetail/actions';
import { styles } from './styles';
import CommentChecklist from '../../../CommentChecklist';

interface ChecklistItemContentProps {
  item: ChecklistItem;
  isInvalid?: boolean;
  onClearInvalid?: (itemId: string) => void;
}

const ChecklistItemContent: React.FC<ChecklistItemContentProps> = ({
  item,
  isInvalid,
  onClearInvalid,
}) => {
  const { t } = useAppTranslation();
  const [selectedFile, setSelectedFile] = useState<FileInfo | null>(null);

  // Get all media from systemFiles and systemVideos (instruction files)
  const systemFiles = item.systemFiles || [];
  const systemVideos = item.systemVideos || [];

  const allSystemMedia: FileInfo[] = [];

  systemFiles.forEach((file: any) => {
    if (file?.url) {
      allSystemMedia.push({
        ...file,
        uri: file.url,
        type: 'file',
      });
    }
  });

  systemVideos.forEach((video: any) => {
    if (video?.url) {
      allSystemMedia.push({
        ...video,
        uri: video.url,
        type: 'video',
      });
    }
  });

  // Determine read-only state
  // For JobReady mode: canUpdate may be undefined (not in API response) which means editable
  // For other modes: canUpdate explicitly set by API
  const isReadOnly = useMemo(() => {
    // If canUpdate is explicitly false, it's read-only
    if (item.canUpdate === false) return true;
    // Otherwise (true or undefined), it's editable
    return false;
  }, [item.canUpdate]);

  const hasSystemMedia = allSystemMedia.length > 0;
  // Support both 'response' and 'responses' field names (JobReady uses 'responses')
  const responsesList = item.responses || item.response || [];
  const hasResponses = responsesList.length > 0;
  const isQIRole = item.userRole === userRole.INSPECTOR;

  // Use detectChecklistMode from helper
  const mode = detectChecklistMode(item);
  const isNotS3 = mode === ChecklistMode.JOB_READY;

  const handleMediaPress = (file: FileInfo) => {
    setSelectedFile(file);
  };

  const handleCloseViewer = () => {
    setSelectedFile(null);
  };

  const showReadOnlyAlert = () => {
    dispatch(
      showAlertAsync({
        visible: true,
        title: t('WARNING'),
        type: 'warning',
        buttonText: t('OK'),
        message: item?.reason || t('CHECKLIST_READ_ONLY'),
        onClose: () => {
          dispatch(hideAlertAsync());
        },
      }),
    );
  };

  const handleCheckboxPress = () => {
    if (isReadOnly) {
      showReadOnlyAlert();
      return;
    }

    if (!isPassValidateFilesByFileSetting(item)) {
      dispatch(
        showConfirmModal({
          visible: true,
          title: t('WARNING'),
          description: t('CHECK_REQUIRED_FILES'),
          confirmText: t('OK'),
          cancelText: t('NOT_NOW'),
          onConfirm: () => {
            dispatch(hideConfirmModal());
            dispatch(
              actionContainer.showCommentChecklistModal({
                visible: true,
                item: item,
                folderName: 'checklist',
                isAutoChecked: true,
                screenKey: item.screenKey, // Pass screenKey for API routing
                notS3: isNotS3, // Skip S3 for JobReady mode
              }),
            );
          },
          onCancel: () => {
            dispatch(hideConfirmModal());
          },
        }),
      );
      return;
    } else {
      dispatch(
        actionContainer.getCommentChecklistAsync({
          id: item.id,
          isChecked: !item.isChecked,
        }),
      );
    }
  };

  // Handle QI toggle actions
  const handleQIToggle = (type: 'yes' | 'no' | 'na') => {
    if (isReadOnly) {
      showReadOnlyAlert();
      return;
    }
    // Determine the auto-check value based on type
    // 'na' -> 'na', 'yes'/'no' -> true
    const autoCheckValue: boolean | 'na' = type === 'na' ? 'na' : true;

    // Validate files before toggling
    if (!isPassValidateFilesByFileSetting(item)) {
      dispatch(
        showConfirmModal({
          visible: true,
          title: t('WARNING'),
          description: t('CHECK_REQUIRED_FILES'),
          confirmText: t('OK'),
          cancelText: t('NOT_NOW'),
          onConfirm: () => {
            dispatch(hideConfirmModal());
            dispatch(
              actionContainer.showCommentChecklistModal({
                visible: true,
                item: item,
                folderName: 'checklist',
                isAutoChecked: autoCheckValue,
                screenKey: item.screenKey, // Pass screenKey for API routing
                notS3: isNotS3, // Skip S3 for JobReady mode
              }),
            );
          },
          onCancel: () => {
            dispatch(hideConfirmModal());
          },
        }),
      );
      return;
    }

    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    const payload: any = {
      id: item.id,
    };

    if (type === 'yes') {
      payload.isChecked = true;
      payload.isNA = false;
    } else if (type === 'no') {
      payload.isChecked = false;
      payload.isNA = false;
    } else if (type === 'na') {
      payload.isChecked = null;
      payload.isNA = true;
    }

    dispatch(actionContainer.getCommentChecklistAsync(payload));
  };

  const handleCommentPress = () => {
    if (isReadOnly) {
      showReadOnlyAlert();
      return;
    }
    dispatch(
      actionContainer.showCommentChecklistModal({
        visible: true,
        item: item,
        folderName: 'checklist',
        screenKey: item.screenKey, // Pass screenKey for API routing
        notS3: isNotS3, // Skip S3 for JobReady mode
        onSubmitSuccess: onClearInvalid, // Clear invalid state after successful submission
      }),
    );
  };

  const renderFileRequirements = () => {
    const fileSettings = item.fileSettings;
    if (!fileSettings || fileSettings.length === 0) return null;

    return fileSettings.map((setting: FileSetting, idx: number) => {
      const hasMin = setting.minFiles > 0;
      const hasMax = setting.maxFiles > 0;

      // Skip if both min and max are 0 (no requirement)
      if (!hasMin && !hasMax) {
        return null;
      }

      // Build requirement text based on min/max values
      let requirementText = '';
      if (hasMin && hasMax) {
        // Both min and max > 0: show "min ~ max"
        requirementText = `${setting.minFiles} ~ ${setting.maxFiles}`;
      } else if (hasMin) {
        // Only min > 0: show "Min: min"
        requirementText = `${t('MIN_FILE')} ${setting.minFiles}`;
      } else if (hasMax) {
        // Only max > 0: show "Max: max"
        requirementText = `${t('MAX_FILE')} ${setting.maxFiles}`;
      }

      return (
        <View key={idx} style={styles.requirementContainer}>
          <Text style={styles.requirementText}>
            {t('REQUIRED')}: {requirementText} {t('PHOTO(S)')}
          </Text>
        </View>
      );
    });
  };

  const renderSystemMedia = () => {
    if (!hasSystemMedia) return null;

    return (
      <View style={styles.systemMediaContainer}>
        <Text style={styles.mediaLabel}>{t('CHECKLIST_FILES_2')}:</Text>
        <View style={styles.mediaContainer}>
          {allSystemMedia.map((file, index) => (
            <FileThumbnail
              key={`${file.id || index}`}
              file={file}
              size="medium"
              onPress={() => handleMediaPress(file)}
              isInstruction
            />
          ))}
        </View>
      </View>
    );
  };

  const renderResponses = () => {
    if (!hasResponses) return null;

    return (
      <View style={styles.responsesContainer}>
        {responsesList.map((response: any, responseIndex: number) => {
          const responseFiles = response.fileEntities || [];

          return (
            <View key={responseIndex} style={styles.responseItem}>
              {/* User name */}
              <Text style={styles.responseUserName}>
                {response.createdName || 'Unknown'}
              </Text>

              {/* Comment text */}
              {response.comment && (
                <Text style={styles.responseComment}>{response.comment}</Text>
              )}

              {/* User's media */}
              {responseFiles.length > 0 && (
                <View style={styles.responseMediaContainer}>
                  {responseFiles.map((file: any, idx: number) => {
                    const fileInfo: FileInfo = {
                      ...file,
                      uri: file.url || file.fileUrl,
                      type: file.fileExtension === '.mp4' ? 'video' : 'file',
                      name: file.fileName || file.name,
                    };

                    return (
                      <FileThumbnail
                        key={`${file.id || idx}`}
                        file={fileInfo}
                        size="medium"
                        onPress={() => handleMediaPress(fileInfo)}
                        readOnly
                      />
                    );
                  })}
                </View>
              )}
            </View>
          );
        })}
      </View>
    );
  };

  // QI Role UI - Yes/No/N/A toggles
  const renderQIRowTop = () => {
    const isYesActive = item.isChecked === true && !item.isNA;
    const isNoActive = item.isChecked === false && !item.isNA;
    const isNAActive = item.isNA === true;

    return (
      <>
        <View style={styles.qiRowTop}>
          <Text style={styles.qiLabel}>{t('IS_COMPLETE')}?</Text>

          {/* Yes Toggle */}
          <Button
            style={styles.qiToggleButton}
            onPress={() => handleQIToggle('yes')}
            activeOpacity={0.7}
          >
            <View
              style={[styles.qiToggle, isYesActive && styles.qiToggleActiveYes]}
            >
              {isYesActive && <View style={styles.qiToggleDot} />}
            </View>
            <Text
              style={[
                styles.qiToggleText,
                isYesActive && styles.qiToggleTextActiveYes,
              ]}
            >
              {t('YES')}
            </Text>
          </Button>

          {/* No Toggle */}
          <Button
            style={styles.qiToggleButton}
            onPress={() => handleQIToggle('no')}
            activeOpacity={0.7}
          >
            <View
              style={[styles.qiToggle, isNoActive && styles.qiToggleActiveNo]}
            >
              {isNoActive && <View style={styles.qiToggleDot} />}
            </View>
            <Text
              style={[
                styles.qiToggleText,
                isNoActive && styles.qiToggleTextActiveNo,
              ]}
            >
              {t('NO')}
            </Text>
          </Button>

          {/* N/A Toggle */}
          <Button
            style={styles.qiToggleButton}
            onPress={() => handleQIToggle('na')}
            activeOpacity={0.7}
          >
            <View
              style={[styles.qiToggle, isNAActive && styles.qiToggleActiveNA]}
            >
              {isNAActive && <View style={styles.qiToggleDot} />}
            </View>
            <Text
              style={[
                styles.qiToggleText,
                isNAActive && styles.qiToggleTextActiveNA,
              ]}
            >
              {t('N/A')}
            </Text>
          </Button>

          {/* Comment Icon */}
          <Button
            style={styles.qiCommentButton}
            onPress={handleCommentPress}
            activeOpacity={0.7}
          >
            <SvgXml
              xml={IconComment(colors.mainColorPrimary)}
              width={24}
              height={24}
            />
          </Button>
        </View>

        {/* Item Name below toggles */}

        <Text style={styles.qiItemName} numberOfLines={5}>
          <Text style={styles.rowNumber}>{item.orderNumber}.</Text>
          {item.name || item.description}
        </Text>
      </>
    );
  };

  // JobReady Mode UI - 4 Radio Options (Complete, In Progress, Not Start, Not Relevant)
  const renderJobReadyRowTop = () => {
    // Map item properties to JobReady options
    // Assuming item has selectedOption property (0=not selected, 1=complete, 2=in progress, 3=not start, 4=not relevant)
    const selectedOption = (item as any).selectedOption || 0;

    // Use options from helper - translate labels here
    const options = JOB_READY_OPTIONS.map(opt => ({
      ...opt,
      label: t(opt.labelKey),
    }));

    const handleOptionPress = (optionValue: number) => {
      if (isReadOnly) {
        showReadOnlyAlert();
        return;
      }

      const selectedOptionValue = optionValue as JobReadyOption;

      // Validate before allowing option selection
      const isValid = isPassValidateJobReady(item, selectedOptionValue);

      if (!isValid) {
        // Validation failed - need comment/file
        // Open CommentChecklist modal with selectedOption
        dispatch(
          showConfirmModal({
            visible: true,
            title: t('WARNING'),
            description: t('CHECK_REQUIRED_FILES'),
            confirmText: t('OK'),
            cancelText: t('NOT_NOW'),
            onConfirm: () => {
              dispatch(hideConfirmModal());
              dispatch(
                actionContainer.showCommentChecklistModal({
                  visible: true,
                  item: item,
                  folderName: 'checklist',
                  screenKey: item.screenKey,
                  notS3: isNotS3,
                  selectedOption: selectedOptionValue, // Pass selected option
                  onSubmitSuccess: onClearInvalid, // Clear invalid state after successful submission
                }),
              );
            },
            onCancel: () => {
              dispatch(hideConfirmModal());
            },
          }),
        );
        return;
      }

      // Validation passed - dispatch action to update JobReady option
      dispatch(
        actionJobDetail.updateJobReadyItemOption({
          itemId: item.id,
          selectedOption: selectedOptionValue,
          screenKey: SCREEN_ENUM.JobReadyChecklistScreen,
        }),
      );

      // Clear invalid state for this item
      onClearInvalid?.(item.id);
    };

    const renderRadioButton = (option: {
      key: number;
      label: string;
      value: number;
    }) => {
      const isSelected = selectedOption === option.value;

      return (
        <Button
          key={option.key}
          style={styles.jobReadyOptionContainer}
          onPress={() => handleOptionPress(option.value)}
          activeOpacity={0.7}
        >
          <View
            style={[
              styles.radioOuter,
              isSelected && styles.radioOuterSelected,
              isReadOnly && styles.radioOuterReadOnly,
            ]}
          >
            {isSelected && (
              <View
                style={[
                  styles.radioInner,
                  isReadOnly && styles.radioInnerReadOnly,
                ]}
              />
            )}
          </View>
          <Text
            style={[
              styles.jobReadyOptionLabel,
              isSelected && styles.jobReadyOptionLabelSelected,
              isReadOnly && styles.jobReadyOptionLabelReadOnly,
            ]}
          >
            {option.label}
          </Text>
        </Button>
      );
    };

    return (
      <View>
        {/* Item Header - Number, Name, Comment Icon in same row */}
        <View
          style={[styles.jobReadyHeader, isInvalid && styles.invalidItemName]}
        >
          <Text style={styles.jobReadyItemNumber}>{item.orderNumber}.</Text>
          <Text style={styles.jobReadyItemName}>
            {item.description || item.name}
          </Text>
          <Button
            style={styles.jobReadyCommentIconButton}
            onPress={handleCommentPress}
            activeOpacity={0.7}
          >
            <SvgXml xml={IconComment(colors.darkBlue)} width={24} height={24} />
          </Button>
        </View>

        {/* 4-Option Radio Grid */}
        <View style={styles.jobReadyOptionsGrid}>
          <View style={styles.jobReadyOptionsRow}>
            {renderRadioButton(options[0])}
            {renderRadioButton(options[1])}
          </View>
          <View style={styles.jobReadyOptionsRow}>
            {renderRadioButton(options[2])}
            {renderRadioButton(options[3])}
          </View>
        </View>
      </View>
    );
  };

  // Default Role UI - Checkbox
  const renderDefaultRowTop = () => {
    return (
      <View style={styles.rowTop}>
        <Button
          style={styles.checkbox}
          onPress={handleCheckboxPress}
          activeOpacity={0.7}
        >
          <View
            style={[
              styles.checkboxBox,
              item.isChecked === true && styles.checkboxBoxChecked,
            ]}
          >
            {item.isChecked === true && (
              <SvgXml xml={IconCheck(colors.white)} width={14} height={14} />
            )}
          </View>
        </Button>
        <Text style={styles.rowNumber}>{item.orderNumber}.</Text>
        <Text style={styles.rowName} numberOfLines={5}>
          {item.name || item.description}
        </Text>
        <Button
          style={styles.checkbox}
          onPress={handleCommentPress}
          activeOpacity={0.7}
        >
          <SvgXml xml={IconComment(colors.darkBlue)} width={24} height={24} />
        </Button>
      </View>
    );
  };

  const renderRowTop = () => {
    switch (mode) {
      case ChecklistMode.JOB_READY:
        return renderJobReadyRowTop();
      case ChecklistMode.QI:
        return renderQIRowTop();
      case ChecklistMode.DEFAULT:
      default:
        return renderDefaultRowTop();
    }
  };

  return (
    <View style={[styles.container, isReadOnly && styles.disabledContainer]}>
      {renderRowTop()}

      {/* File Requirements */}
      {renderFileRequirements()}

      {/* System Media (Checklist Files) */}
      {renderSystemMedia()}

      {/* User Responses */}
      {renderResponses()}

      {/* File Viewer */}
      {selectedFile && (
        <FileViewer
          visible={!!selectedFile}
          onClose={handleCloseViewer}
          file={selectedFile}
        />
      )}
    </View>
  );
};

export default ChecklistItemContent;
