import { call, put, takeEvery } from 'redux-saga/effects';
import {
  GET_FRIEND_REFERRAL_ASYNC,
  GET_FRIEND_REFERRAL_DETAIL_ASYNC,
  GET_FRIEND_REFERRAL_DETAIL_FAILED,
  GET_FRIEND_REFERRAL_DETAIL_PROGRESS,
  GET_FRIEND_REFERRAL_DETAIL_SUCCESS,
  GET_FRIEND_REFERRAL_FAILED,
  GET_FRIEND_REFERRAL_PROGRESS,
  GET_FRIEND_REFERRAL_SUCCESS,
} from './contants';
import { ResponseApi } from '../../store/types';
import {
  fetchReferFriend,
  fetchReferFriendDetail,
} from '../../../api/referFriend';
import { HIDE_LOADING_OVERLAY, SHOW_LOADING_OVERLAY } from '../app/constants';
import { logger } from '../../../utils';

const getReferFriend = function* (): Generator<any, void, any> {
  try {
    yield put({ type: GET_FRIEND_REFERRAL_PROGRESS, payload: true });
    yield put({ type: SHOW_LOADING_OVERLAY });
    const response = (yield call(fetchReferFriend)) as ResponseApi;

    if (response.status !== 200) {
      yield put({
        type: GET_FRIEND_REFERRAL_FAILED,
        payload: response.message,
      });
      return;
    }

    yield put({ type: GET_FRIEND_REFERRAL_SUCCESS, payload: response.data });
  } catch (error) {
  } finally {
    yield put({ type: GET_FRIEND_REFERRAL_PROGRESS, payload: false });
    yield put({ type: HIDE_LOADING_OVERLAY });
  }
};

const getReferFriendDetail = function* (action: {
  type: string;
  payload: string;
}): Generator<any, void, any> {
  try {
    yield put({ type: SHOW_LOADING_OVERLAY });
    yield put({ type: GET_FRIEND_REFERRAL_DETAIL_PROGRESS, payload: true });
    const response = (yield call(
      fetchReferFriendDetail,
      action.payload,
    )) as ResponseApi;

    if (response.status !== 200) {
      yield put({
        type: GET_FRIEND_REFERRAL_DETAIL_FAILED,
        payload: response.message,
      });
      return;
    }

    yield put({
      type: GET_FRIEND_REFERRAL_DETAIL_SUCCESS,
      payload: response.data,
    });
  } catch (error) {
    logger('getReferFriendDetail', error);
  } finally {
    yield put({ type: HIDE_LOADING_OVERLAY });
    yield put({ type: GET_FRIEND_REFERRAL_DETAIL_PROGRESS, payload: false });
  }
};

export default function* referFriendSaga() {
  yield takeEvery(GET_FRIEND_REFERRAL_ASYNC, getReferFriend);
  yield takeEvery(GET_FRIEND_REFERRAL_DETAIL_ASYNC, getReferFriendDetail);
}
