import {
  CommonActions,
  createNavigationContainerRef,
  StackActions,
} from '@react-navigation/native';
import { ARR_MAX_Y_FAB } from '../utils';

export const navigationRef = createNavigationContainerRef<any>();

export const NavigationService = {
  navigate: (name: string, params?: any) => {
    if (navigationRef.isReady()) {
      navigationRef.navigate(name, params);
    }
  },
  replace: (name: string, params?: any) => {
    if (navigationRef.isReady()) {
      navigationRef.dispatch(StackActions.replace(name, params));
    }
  },
  reset: (name: string, params?: any) => {
    if (navigationRef.isReady()) {
      navigationRef.dispatch(
        CommonActions.reset({
          index: 0,
          routes: [{ name, params }],
        }),
      );
    }
  },
  goBack: async () => {
    if (navigationRef.isReady() && navigationRef.canGoBack()) {
      navigationRef.goBack();
      const redux = await import('auth/redux');
      const currentRoute = NavigationService.getCurrentRoute();
      if (ARR_MAX_Y_FAB?.includes(currentRoute as string)) {
        redux.store.dispatch(redux.actionContainer?.setIsFabVisible(true));
      } else {
        redux.store.dispatch(redux.actionContainer?.setIsFabVisible(false));
      }
    }
  },
  // Navigate to a specific tab in BottomTabNavigator
  navigateToTab: (tabName: string, params?: any) => {
    if (navigationRef.isReady()) {
      navigationRef.navigate('BottomTabNavigator', {
        screen: tabName,
        params,
      });
    }
  },
  // Check if navigation is ready
  isReady: () => navigationRef.isReady(),
  // Get current route name
  getCurrentRoute: () => {
    if (navigationRef.isReady()) {
      return navigationRef.getCurrentRoute()?.name;
    }
    return null;
  },
};
