import {
  BaseContainer,
  HeaderBase,
  Input,
  SCREEN_WIDTH,
} from 'tradewize-component';
import { styles } from './styles';
import React, { useRef, useState } from 'react';
import { NavigationService } from '../../services/NavigationService';
import { ActivityIndicator, FlatList, View } from 'react-native';
import { useNetwork } from '../../hooks/useNetwork';
import { SvgXml } from 'react-native-svg';
import { IconSearch } from '../../assets/svg';
import colors from '../../theme/colors';
import { useSelector } from 'react-redux';
import UserCard from './components/userCard';
import { useAppTranslation } from '../../hooks/useAppTranslation';
import { logger } from '../../utils';

export default function NetworkScreen() {
  const { t } = useAppTranslation();
  const [searchText, setSearchText] = useState('');
  const pageNumber = useRef(1);

  const { onLoadMore, onRefresh, onSearch } = useNetwork();

  const networkData = useSelector(
    (state: any) => state?.network?.network?.data,
  );
  const isLoading = useSelector(
    (state: any) => state?.network?.network?.isLoading,
  );
  const isLoadingOverlay = useSelector(
    (state: any) => state?.app?.loadingOverlay?.isVisible,
  );

  const data = networkData?.items ?? [];
  const currentPage = networkData?.pageIndex ?? 1;
  const totalPage = networkData?.totalPage ?? 1;
  const hasMore = currentPage < totalPage && totalPage > 0;

  const handleEndReached = () => {
    if (!hasMore || isLoadingOverlay || isLoading) return;
    const nextPage = pageNumber.current + 1;
    try {
      onLoadMore(nextPage, searchText);
      pageNumber.current = nextPage;
    } catch (error) {
      logger('error onLoadMore', error);
    }
  };

  const renderFooter = () => {
    if (!isLoading || isLoadingOverlay) {
      return null;
    }
    return (
      <View style={styles.footerContainer}>
        <ActivityIndicator size="small" color={colors.mainColorPrimary} />
      </View>
    );
  };

  const handleRefresh = () => {
    try {
      onRefresh(searchText);
      pageNumber.current = 1;
    } catch (error) {
      logger('error handleRefresh', error);
    }
  };

  return (
    <BaseContainer style={styles.container}>
      <HeaderBase
        title={t('NETWORK')}
        onPressBack={() => {
          NavigationService.goBack();
        }}
      />
      <View style={styles.bodyContainer}>
        <Input
          containerStyle={styles.containerInput}
          leftIcon={
            <SvgXml
              xml={IconSearch(colors.mainColorPrimary)}
              width={SCREEN_WIDTH * 0.06}
              height={SCREEN_WIDTH * 0.06}
            />
          }
          fullWidth={false}
          placeholder={t('SEARCH')}
          placeholderTextColor={colors.grayScale70}
          inputContainerStyle={styles.inputContainerStyle}
          inputStyle={styles.inputStyle}
          borderColorActive={colors.mainColorPrimary}
          cursorColor={colors.mainColorPrimary}
          selectionColor={colors.mainColorPrimary}
          onChangeText={text => {
            setSearchText(text);
          }}
          value={searchText}
          returnKeyType="search"
          onBlur={() => {
            onSearch(searchText);
          }}
        />
        <FlatList
          style={styles.flatList}
          contentContainerStyle={styles.flatListContentContainer}
          data={data}
          renderItem={({ item }) => (
            <UserCard user={item} searchText={searchText} />
          )}
          keyExtractor={(item, index) => `${item.id}-${index}`}
          showsVerticalScrollIndicator={false}
          onEndReached={handleEndReached}
          onEndReachedThreshold={0.1}
          ListFooterComponent={renderFooter}
          onRefresh={handleRefresh}
          refreshing={false}
        />
      </View>
    </BaseContainer>
  );
}
