import { useCallback, useEffect, useRef, useState } from 'react';
import { ScrollView } from 'react-native';
import { useDispatch, useSelector } from 'react-redux';
import dayjs from 'dayjs';
import Toast from 'react-native-toast-message';
import { RootState } from '../../../Auth/src/redux/store/types';
import { actionJobDetail } from '../../../Auth/src/redux/features/jobDetail/actions';
import {
  ChecklistItem,
  JobReadyData,
  JobReadyOption,
  JobReadyChecklistItem,
  checklistCategory,
  DeliveryAvailableDate,
} from '../types/jobDetail.type';
import { SCREEN_ENUM } from '../types/global';
import { showAlertAsync, hideAlertAsync } from '../../../Auth/src/redux/features/app/actions';
import { NavigationService } from '../services/NavigationService';
import { useAppTranslation } from './useAppTranslation';

const CATEGORY_PRIORITY = [
  checklistCategory.JobStart,
  checklistCategory.General,
  checklistCategory.Material,
  checklistCategory.MaterialDelivery,
  checklistCategory.EndOfDay,
];

interface UseJobReadyChecklistProps {
  scheduleActivityId: string;
  workOrderId?: string;
}

export const useJobReadyChecklist = ({
  scheduleActivityId,
  workOrderId,
}: UseJobReadyChecklistProps) => {
  const { t } = useAppTranslation();
  const dispatch = useDispatch();
  const scrollViewRef = useRef<ScrollView>(null);
  const scrollY = useRef<number>(0);

  const jobDetailState = useSelector((state: RootState) => state.jobDetail);

  // Safety: ensure data is always valid
  const jobReadyData = jobDetailState?.jobReadyData?.data ?? null;
  const isLoading = jobDetailState?.jobReadyData?.isLoading ?? false;
  const rawChecklists = jobDetailState?.checklists?.[SCREEN_ENUM.JobReadyChecklistScreen]?.data;
  const checklists = Array.isArray(rawChecklists) ? (rawChecklists as ChecklistItem[]) : [];

  const [isModalVisible, setIsModalVisible] = useState(false);
  const [selectedMedia, setSelectedMedia] = useState<any>(null);
  const [invalidItemIds, setInvalidItemIds] = useState<string[]>([]);

  // Computed values from actual API fields
  const isViewOnly = jobReadyData?.isViewOnly ?? false;

  console.log('isViewOnly', isViewOnly);
  console.log('jobReadyData', jobReadyData);
  
  
  // Compute isReady: all checklists must have a selection (not NOT_SELECTED)
  const isReady = jobReadyData?.status === 2;
  
  // deliveryAvailbleDates is array of objects (API typo: 'Availble')
  const deliveryAvailableDates = jobReadyData?.deliveryAvailbleDates || [];

  // Fetch data on mount
  useEffect(() => {
    if (scheduleActivityId) {
      dispatch(actionJobDetail.getJobReadyDataAsync({ 
        scheduleActivityId,
        screenKey: SCREEN_ENUM.JobReadyChecklistScreen,
      }));
    }

    return () => {
      dispatch(actionJobDetail.clearJobReadyData(SCREEN_ENUM.JobReadyChecklistScreen));
    };
  }, [scheduleActivityId, dispatch]);

  // Get checklist items for submit payload
  const getChecklistItemsForSubmit = useCallback(() => {
    return checklists.map((item: ChecklistItem) => ({
      id: item.id,
      selectedOption: item.selectedOption || JobReadyOption.NOT_SELECTED,
    }));
  }, [checklists]);

  // Find first item without selection for scroll
  const findFirstUnselectedItem = useCallback(() => {
    const unselectedItems = checklists
      .filter((item: ChecklistItem) =>
        item.selectedOption === JobReadyOption.NOT_SELECTED ||
        item.selectedOption === undefined
      )
      .sort((a, b) => {
        const indexA = CATEGORY_PRIORITY.indexOf(a.category);
        const indexB = CATEGORY_PRIORITY.indexOf(b.category);
        return (indexA === -1 ? Infinity : indexA) - (indexB === -1 ? Infinity : indexB);
      });

    return unselectedItems[0];
  }, [checklists]);

  // Validate all checklists have selection
  const validateChecklists = useCallback((): boolean => {
    const unselectedIds = checklists
      .filter((item: ChecklistItem) =>
        item.selectedOption === JobReadyOption.NOT_SELECTED ||
        item.selectedOption === undefined
      )
      .map((item: ChecklistItem) => item.id);

    if (unselectedIds.length > 0) {
      // Set invalid item IDs for UI highlighting
      setInvalidItemIds(unselectedIds);
      
      // Show toast instead of modal
      Toast.show({
        type: 'error',
        text1: t('WARNING'),
        text2: t('PLEASE_SELECT_OPTIONS_FOR_CHECKLIST_ALL'),
        position: 'top',
        visibilityTime: 3000,
      });
      return false;
    }

    setInvalidItemIds([]);
    return true;
  }, [checklists, t]);

  // Handle option selection
  const handleSelectOption = useCallback((
    itemId: string,
    option: JobReadyOption
  ) => {
    // Clear invalid state for this item when selected
    setInvalidItemIds(prev => prev.filter(id => id !== itemId));
    
    // Update local state through Redux
    dispatch(
      actionJobDetail.updateJobReadyItemOption({
        itemId,
        selectedOption: option,
        screenKey: SCREEN_ENUM.JobReadyChecklistScreen,
      })
    );
  }, [dispatch]);

  // Handle save comment with files
  const handleSaveComment = useCallback((
    item: ChecklistItem,
    comment: string,
    fileEntities: any[],
    onSuccess?: () => void
  ) => {
    dispatch(
      actionJobDetail.saveJobReadyItemAsync({
        itemId: item.id,
        selectedOption: item.selectedOption || JobReadyOption.NOT_SELECTED,
        comment,
        fileEntities,
        screenKey: SCREEN_ENUM.JobReadyChecklistScreen,
        onSuccess: () => {
          // Refresh data after save
          if (scheduleActivityId) {
            dispatch(
              actionJobDetail.getJobReadyDataAsync({ 
                scheduleActivityId,
                screenKey: SCREEN_ENUM.JobReadyChecklistScreen,
              }),
            );
          }
          if (onSuccess) onSuccess();
        },
      })
    );
  }, [dispatch, scheduleActivityId]);

  // Handle submit ready
  const handleSubmitReady = useCallback( async () => {
    if (isViewOnly) {
      dispatch(
        showAlertAsync({
          visible: true,
          title: t('WARNING'),
          type: 'warning',
          buttonText: t('OK'),
          message: t('CHECKLIST_READ_ONLY'),
          onClose: () => dispatch(hideAlertAsync()),
        })
      );
      return;
    }

    if (!validateChecklists()) {
      // Scroll to first unselected item
      const firstUnselected = findFirstUnselectedItem();
      if (firstUnselected && scrollViewRef.current) {
        // Find item index for rough scroll position
        const index = checklists.findIndex((i: ChecklistItem) => i.id === firstUnselected.id);
        const scrollPosition = index * 100; // Approximate height
        scrollViewRef.current.scrollTo({ y: scrollPosition, animated: true });
      }
      return;
    }

    if (!workOrderId || !scheduleActivityId) return;

    dispatch(
      actionJobDetail.submitJobReadyFormAsync({
        workOrderId,
        scheduleActivityId,
        checklistItems: getChecklistItemsForSubmit(),
        onSuccess: async () => {
          // Navigate back to JobDetail and refetch
          NavigationService.goBack();
          if (workOrderId) {
            const redux = await import('auth/redux');
            dispatch(redux.actionContainer.getWorkOrderDetailAsync({ id: workOrderId }));
          }
        },
      })
    );
  }, [
    isViewOnly,
    checklists,
    dispatch,
    t,
    validateChecklists,
    findFirstUnselectedItem,
    getChecklistItemsForSubmit,
    workOrderId,
    scheduleActivityId,
  ]);

  // Handle reschedule
  const handleReschedule = useCallback(async (values: {
    dateSchedule: { dateDelivery: string };
    reason: string;
  }) => {
    if (isViewOnly) {
      dispatch(
        showAlertAsync({
          visible: true,
          title: t('WARNING'),
          type: 'warning',
          buttonText: t('OK'),
          message: t('CHECKLIST_READ_ONLY'),
          onClose: () => dispatch(hideAlertAsync()),
        })
      );
      return;
    }

    if (!workOrderId || !scheduleActivityId) return;

    dispatch(
      actionJobDetail.submitJobReadyFormAsync({
        workOrderId,
        scheduleActivityId,
        checklistItems: getChecklistItemsForSubmit(),
        onSuccess: async () => {
          NavigationService.goBack();
          if (workOrderId) {
            const redux = await import('auth/redux');
            dispatch(redux.actionContainer.getWorkOrderDetailAsync({ id: workOrderId }));
          }
        },
      })
    );
  }, [
    isViewOnly,
    dispatch,
    t,
    getChecklistItemsForSubmit,
    workOrderId,
    scheduleActivityId,
  ]);

  // Group checklists by category
  const groupedChecklists = useCallback(() => {
    const groups: { [key: string]: ChecklistItem[] } = {};
    checklists.forEach((item: ChecklistItem) => {
      const categoryName = checklistCategory[item.category] || t('UNCATEGORIZED');
      if (!groups[categoryName]) {
        groups[categoryName] = [];
      }
      groups[categoryName].push(item);
    });
    return groups;
  }, [checklists, t]);

  // Format delivery dates for dropdown
  const formattedDeliveryDates = useCallback(() => {
    return deliveryAvailableDates.map((dateObj: DeliveryAvailableDate, index: number) => {
      return {
        key: index,
        id: dateObj.id,
        value: dayjs(dateObj.delivery).format('dddd, MMMM DD, YYYY'),
        dateDelivery: dateObj.delivery,
        dateInstallation: dateObj.installation,
        dateProjectReady: dateObj.projectReady,
      };
    });
  }, [deliveryAvailableDates]);

  // Clear invalid state for a specific item
  const clearInvalidItem = useCallback((itemId: string) => {
    setInvalidItemIds(prev => prev.filter(id => id !== itemId));
  }, []);

  return {
    // Data
    jobReadyData,
    checklists,
    isLoading,
    isReady,
    isViewOnly,

    // UI state
    isModalVisible,
    setIsModalVisible,
    selectedMedia,
    setSelectedMedia,
    invalidItemIds,
    clearInvalidItem,

    // Refs
    scrollViewRef,
    scrollY,

    // Actions
    handleSelectOption,
    handleSaveComment,
    handleSubmitReady,
    handleReschedule,
    validateChecklists,

    // Helpers
    groupedChecklists: groupedChecklists(),
    formattedDeliveryDates: formattedDeliveryDates(),
    getChecklistItemsForSubmit,
    findFirstUnselectedItem,
  };
};

export default useJobReadyChecklist;
