import React, { useState } from 'react';
import { View } from 'react-native';
import { Button, Text } from 'tradewize-component';
import { colors } from '../../theme';
import { useAppTranslation } from '../../hooks/useAppTranslation';
import {
  checklistCategory,
  ChecklistItem,
  ChecklistMode,
} from '../../types/jobDetail.type';
import { useSelector } from 'react-redux';
import { RootState } from '../../../../Auth/src/redux/store/types';
import CategorySection from './components/CategorySection';
import { styles } from './styles';
import { detectChecklistModeFromItems } from '../../helper/checkList.helpter';

interface ChecklistProps {
  screenKey: string;
  invalidItemIds?: string[];
  onClearInvalid?: (itemId: string) => void;
}

// Category configuration matching the backend enum
const CategoryConfig = {
  [checklistCategory.JobStart]: {
    color: colors.alertColorSuccess,
    icon: 'play-circle',
    label: 'JOB_START',
  },
  [checklistCategory.General]: {
    color: colors.mainColorPrimary,
    icon: 'list-check',
    label: 'GENERAL',
  },
  [checklistCategory.EndOfDay]: {
    color: colors.alertColorWarning,
    icon: 'flag-checkered',
    label: 'END_OF_DAY',
  },
  [checklistCategory.Material]: {
    color: colors.cyanDark,
    icon: 'list-check',
    label: 'MATERIAL',
  },
  [checklistCategory.MaterialDelivery]: {
    color: colors.lightBlue,
    icon: 'list-check',
    label: 'MATERIAL_DELIVERY',
  },
};



const Checklist: React.FC<ChecklistProps> = ({
  screenKey,
  invalidItemIds,
  onClearInvalid,
}) => {
  const { t } = useAppTranslation();
  const checklistsData = useSelector(
    (state: RootState) => state.jobDetail?.checklists?.[screenKey]?.data,
  );
  // Safety: ensure checklists is always an array
  const checklists: any = Array.isArray(checklistsData) ? checklistsData : [];

  const [expandedCategories, setExpandedCategories] = useState<{
    [key: string]: boolean;
  }>(
    Object.values(checklistCategory).reduce(
      (acc, key) => ({ ...acc, [key]: true }),
      {} as { [key: string]: boolean },
    ),
  );

  const toggleCategory = (categoryKey: string) => {
    setExpandedCategories(prev => ({
      ...prev,
      [categoryKey]: !prev[categoryKey],
    }));
  };

  const getCheckedCount = (items: ChecklistItem[] | undefined) => {
    if (!Array.isArray(items)) return 0;
    return items.filter(item => item.isChecked).length;
  };

  const totalChecked = getCheckedCount(checklists);
  const totalCount = checklists?.length || 0;

  // Detect checklist mode from items
  const checklistMode = detectChecklistModeFromItems(checklists);

  // Group checklists by category
  const groupedChecklists = (checklists || []).reduce(
    (acc: { [key: string]: ChecklistItem[] }, item: any) => {
      const categoryKey = String(item.category);
      if (!acc[categoryKey]) {
        acc[categoryKey] = [];
      }
      acc[categoryKey].push(item);
      return acc;
    },
    {} as { [key: string]: ChecklistItem[] },
  );

  const categoryKeys = Object.keys(groupedChecklists).sort(
    (a, b) => Number(a) - Number(b),
  );

  console.log('checklistMode', checklistMode);

  return (
    <View style={[styles.container]}>
      {/* Main Header */}
      <View style={styles.header}>
        <Text style={styles.headerText}>
          {checklistMode !== ChecklistMode.JOB_READY
            ? t('ROLE_CHECKLIST')
            : t('CHECKLIST')}
        </Text>
        {/* Hide badge count for JOB_READY mode */}
        {checklistMode !== ChecklistMode.JOB_READY && (
          <View style={styles.headerBadge}>
            <Text style={styles.headerBadgeText}>
              {totalChecked}/{totalCount}
            </Text>
          </View>
        )}
      </View>

      {/* Category Groups */}
      <View style={styles.content}>
        {categoryKeys.map(categoryKey => {
          const categoryEnum = Number(categoryKey) as checklistCategory;
          const config = CategoryConfig[categoryEnum];

          // Skip if category not in config
          if (!config) return null;

          const items = groupedChecklists[categoryKey];

          return (
            <CategorySection
              key={categoryKey}
              categoryKey={categoryKey}
              categoryEnum={categoryEnum}
              items={items}
              expandedCategories={expandedCategories}
              toggleCategory={toggleCategory}
              mode={checklistMode}
              invalidItemIds={invalidItemIds}
              onClearInvalid={onClearInvalid}
            />
          );
        })}

        {categoryKeys.length === 0 && (
          <Text style={styles.emptyText}>{t('NO_DATA')}</Text>
        )}
      </View>
    </View>
  );
};

export default Checklist;
