import { useEffect } from 'react';
import { useDispatch } from 'react-redux';
import { logger } from '../utils';
interface UseReferFriendJobDetailParams {
  jobId: string;
}
export const useReferFriendJobDetail = ({
  jobId,
}: UseReferFriendJobDetailParams) => {
  const dispatch = useDispatch();

  const fetchReferFriendJobDetail = async () => {
    try {
      const redux = await import('auth/redux');
      dispatch(redux.actionContainer.getFriendReferralDetailAsync(jobId));
    } catch (error) {
      logger('fetchReferFriendJobDetail', error);
    }
  };

  useEffect(() => {
    fetchReferFriendJobDetail();
  }, [jobId]);
};
