import { FlatList, ScrollView, SectionList, View } from 'react-native';
import Loading from '../loading';
import { styles } from './styles';
import { useDispatch, useSelector } from 'react-redux';
import CardItemVideo from '../CardItemVideo';
import HeaderCard from '../HeaderCard';
import { useCallback, useEffect, useRef, useState } from 'react';
import { logger } from '../../../../utils';
import { SCREEN_ENUM } from '../../../../types/global';
import { NavigationService } from '../../../../services/NavigationService';
import { useAppTranslation } from '../../../../hooks/useAppTranslation';

function getAllTutorials(tutorialsByCompany: any, safetyGuidByCompany?: any) {
  const tutorialsFromCompany =
    tutorialsByCompany
      ?.flatMap((company: any) => company?.tutorials || [])
      ?.map((tutorial: any) => ({
        ...tutorial,
        subTitle: tutorial?.subTitle ? tutorial?.subTitle : {},
      })) || [];

  const tutorialsFromSafetyGuid =
    safetyGuidByCompany
      ?.flatMap((company: any) => company?.tutorials || [])
      ?.map((tutorial: any) => ({
        ...tutorial,
        subTitle: tutorial?.subTitle ? tutorial?.subTitle : {},
      })) || [];

  const watchedCountCompany = tutorialsFromCompany?.filter(
    (t: any) => t.isWatched,
  ).length;
  const watchedCountSafetyGuid = tutorialsFromSafetyGuid?.filter(
    (t: any) => t.isWatched,
  ).length;

  return {
    tutorialsFromCompany,
    tutorialsFromSafetyGuid,
    watchedCountCompany,
    watchedCountSafetyGuid,
    totalTutorialsSafetyGuid: tutorialsFromSafetyGuid?.length || 0,
    totalTutorialsCompany: tutorialsFromCompany?.length || 0,
  };
}

const QualityGuide = ({ isLoading }: { isLoading: boolean }) => {
  const { t } = useAppTranslation();
  const dispatch = useDispatch();
  const initializedRef = useRef(false);

  const qualityGuides = useSelector((state: any) => state.training.myTrainings);
  const [isShowQualityGuide, setIsShowQualityGuide] = useState(true);
  const [isShowQualityGuideTutorial, setIsShowQualityGuideTutorial] =
    useState(true);
  const [isShowViewAllTraining, setIsShowViewAllTraining] = useState<number[]>([
    0,
  ]);
  const [sections, setSections] = useState<
    { title: string; data: any[]; index: number }[]
  >([]);

  const {
    tutorialsFromCompany,
    tutorialsFromSafetyGuid,
    watchedCountCompany,
    watchedCountSafetyGuid,
    totalTutorialsSafetyGuid,
    totalTutorialsCompany,
  } = getAllTutorials(
    qualityGuides?.data?.tutorialsByCompany,
    qualityGuides?.data?.safetyGuidByCompany,
  );

  const handleShowViewAllButton = useCallback(
    (section: any) => {
      try {
        setSections(prev => {
          const copySections = [...prev];
          const sectionsData = qualityGuides?.data?.trainings?.map(
            (item: any, index: number) => ({
              title: item?.companyName || '',
              data: [item],
              index: index,
            }),
          );

          const selectObj: any = copySections?.find(
            (item: any) => item.index === section.index,
          );

          if (selectObj?.data?.length > 0) {
            const newSections = copySections?.map((el: any) => {
              if (el.index === section.index) {
                return {
                  ...el,
                  data: [],
                };
              }
              return el;
            });
            return newSections;
          }

          if (!selectObj?.data?.length) {
            const filterSections = sectionsData?.filter(
              (el: any) => el.index === section.index,
            );
            const newSections = copySections?.map((el: any) => {
              if (el.index === section.index) {
                return {
                  ...el,
                  data: filterSections?.[0]?.data,
                };
              }
              return el;
            });
            return newSections;
          }

          return copySections;
        });
      } catch (error) {
        logger('error handleShowViewAllButton', error);
      }
    },
    [qualityGuides?.data?.trainings],
  );

  const handlePressItem = useCallback(
    async (
      data: any,
      type: 'training' | 'tutorial_company' | 'tutorial_safety' = 'training',
    ) => {
      try {
        const redux = await import('auth/redux');
        if (!data?.isWatched) {
          if (type !== 'training') {
            dispatch(
              redux.actionContainer.markAsWatchedAsync({
                id: data?.id,
                typeQualityGuide: true,
                typeTutorial: type,
              }),
            );
          } else {
            dispatch(redux.actionContainer.markWatchedTrainingAsync(data?.id));
          }
        }
      } catch (error) {
        logger('error handlePressItem', error);
      }
    },
    [dispatch],
  );

  useEffect(() => {
    const fetchData = async () => {
      try {
        const trainings = qualityGuides?.data?.trainings;
        if (!trainings?.length) return;

        const sectionsData = trainings.map((item: any, index: number) => ({
          title: item?.companyName || '',
          data: initializedRef.current
            ? isShowViewAllTraining.includes(index)
              ? [item]
              : []
            : index === 0
            ? [item]
            : [],
          index,
        }));

        setSections(sectionsData);

        if (!initializedRef.current) {
          setIsShowViewAllTraining([0]);
          initializedRef.current = true;
        }
      } catch (error) {
        logger('error fetchData', error);
      }
    };

    fetchData();
  }, [qualityGuides?.data?.trainings, isShowViewAllTraining]);

  const headerConfig: Record<
    string,
    {
      isShow: boolean;
      setIsShow: React.Dispatch<React.SetStateAction<boolean>>;
      watchedCount: number;
      totalTutorials: number;
    }
  > = {
    SAFETYGUID: {
      isShow: isShowQualityGuideTutorial,
      setIsShow: setIsShowQualityGuideTutorial,
      watchedCount: watchedCountSafetyGuid,
      totalTutorials: totalTutorialsSafetyGuid,
    },
    ROLE_TYPES: {
      isShow: isShowQualityGuide,
      setIsShow: setIsShowQualityGuide,
      watchedCount: watchedCountCompany,
      totalTutorials: totalTutorialsCompany,
    },
  };

  const renderHeaderComponent = (title: string) => {
    const config = headerConfig[title] || headerConfig.ROLE_TYPES;

    return (
      <HeaderCard
        titleSystem={t(title)}
        isShowViewAllButton={config.isShow}
        setIsShowViewAllButton={config.setIsShow}
        watchedCount={config.watchedCount}
        totalTutorials={config.totalTutorials}
        styleContainer={!config.isShow && styles.headerContainerSystem}
      />
    );
  };

  useEffect(() => {
    if (sections && !sections?.length && tutorialsFromCompany?.length > 0) {
      setIsShowQualityGuide(false);
    } else {
      setIsShowQualityGuide(true);
    }
  }, [tutorialsFromCompany?.length, sections]);

  useEffect(() => {
    if (
      sections &&
      !sections?.length &&
      tutorialsFromCompany?.length <= 0 &&
      tutorialsFromSafetyGuid?.length > 0
    ) {
      setIsShowQualityGuideTutorial(false);
    } else {
      setIsShowQualityGuideTutorial(true);
    }
  }, [tutorialsFromSafetyGuid?.length, sections]);

  return (
    <View style={styles.container}>
      <ScrollView>
        <SectionList
          scrollEnabled={false}
          style={styles.list}
          contentContainerStyle={styles.listContent}
          sections={sections}
          renderItem={({ item }) => {
            const arrayTrainings =
              item?.trainings?.map((el: any) => {
                return {
                  ...el,
                  subTitle: el?.subTitle || {},
                  title: el?.courseName,
                  description: el?.content,
                  thumbnailUrl: el?.bannerPng,
                  isWatched: el?.isWatched,
                  isPassed: el?.isPassed,
                  isHasQuestion: el?.isHasQuestion,
                };
              }) || [];
            return (
              <FlatList
                scrollEnabled={false}
                showsVerticalScrollIndicator={false}
                data={arrayTrainings}
                renderItem={({ item: training, index }) => {
                  return (
                    <CardItemVideo
                      onTakeTest={() => {
                        NavigationService.navigate(
                          SCREEN_ENUM.TakeTheTestScreen,
                          {
                            trainingId: training?.id,
                            companyId: item?.companyId,
                          },
                        );
                      }}
                      onPress={data => handlePressItem(data, 'training')}
                      data={training}
                      variant="quality"
                      styleContainer={[
                        styles.cardItemVideo,
                        styles.cardItemVideoQuality,
                        index === 0 && styles.cardItemVideoFirst,
                        index !== arrayTrainings?.length - 1 &&
                          styles.cardItemVideoCenterItem,
                        index === arrayTrainings?.length - 1 &&
                          styles.cardItemVideoLastItem,
                      ]}
                    />
                  );
                }}
                keyExtractor={(training, index) => training?.id + index}
              />
            );
          }}
          renderSectionHeader={({ section }) => {
            const sectionsData = qualityGuides?.data?.trainings?.map(
              (item: any, index: number) => ({
                title: item?.companyName || '',
                data: [item],
                index: index,
              }),
            );
            const selectObj: any = sectionsData?.find(
              (item: any) => item.index === section.index,
            );

            const allTrainings = selectObj?.data?.flatMap(
              (company: any) => company?.trainings || [],
            );

            const watchedCountTrainings = allTrainings?.filter(
              (training: any) => training?.isWatched,
            )?.length;

            const testCount = allTrainings?.filter(
              (training: any) => training?.isPassed,
            )?.length;
            const totalTestCount = allTrainings?.filter(
              (training: any) => training?.trainingTestCount > 0,
            )?.length;

            return (
              <HeaderCard
                styleContainer={[
                  styles.headerContainer,
                  !isShowViewAllTraining?.includes(section?.index) &&
                    styles.headerCardContainer,
                  isShowViewAllTraining?.includes(section?.index) &&
                    styles.headerContainerShowAllButton,
                ]}
                watchedCount={watchedCountTrainings}
                titleQuality={section.title}
                variant="quality"
                totalTutorials={allTrainings?.length}
                testCount={testCount}
                totalTestCount={totalTestCount}
                isShowViewAllButton={isShowViewAllTraining?.includes(
                  section?.index,
                )}
                setIsShowViewAllButton={() => {
                  if (isShowViewAllTraining?.includes(section?.index)) {
                    setIsShowViewAllTraining((prev: any) => {
                      const copyPrev = [...prev];
                      return copyPrev?.filter(
                        (item: number) => item !== section?.index,
                      );
                    });
                  } else {
                    setIsShowViewAllTraining((prev: any) => {
                      const copyPrev = [...prev];
                      return [...copyPrev, section?.index];
                    });
                  }
                }}
                onShowViewAllButton={() => {
                  handleShowViewAllButton(section);
                }}
              />
            );
          }}
          keyExtractor={(item, index) => item?.id + index}
        />

        <FlatList
          scrollEnabled={false}
          style={styles.list}
          contentContainerStyle={[
            styles.listContentSystem,
            !isShowQualityGuide && styles.listContentShowAllButton,
          ]}
          data={!isShowQualityGuide ? tutorialsFromCompany : []}
          renderItem={({ item }) => (
            <CardItemVideo
              onPress={data => handlePressItem(data, 'tutorial_company')}
              data={item}
            />
          )}
          keyExtractor={(item, index) => item?.id + index}
          ListHeaderComponent={() => renderHeaderComponent('ROLE_TYPES')}
        />

        <FlatList
          scrollEnabled={false}
          style={styles.list}
          contentContainerStyle={[
            styles.listContentSystem,
            !isShowQualityGuideTutorial && styles.listContentShowAllButton,
          ]}
          data={!isShowQualityGuideTutorial ? tutorialsFromSafetyGuid : []}
          renderItem={({ item }) => (
            <CardItemVideo
              onPress={data => handlePressItem(data, 'tutorial_safety')}
              data={item}
            />
          )}
          keyExtractor={(item, index) => item?.id + index}
          ListHeaderComponent={() => renderHeaderComponent('SAFETYGUID')}
        />
      </ScrollView>
      {isLoading && <Loading />}
    </View>
  );
};

export default QualityGuide;
