import BottomSheet, {
  BottomSheetBackdrop,
  BottomSheetBackdropProps,
} from '@gorhom/bottom-sheet';
import {
  forwardRef,
  useImperativeHandle,
  useMemo,
  useRef,
  useState,
} from 'react';
import {
  Image,
  Keyboard,
  Text,
  TouchableNativeFeedback,
  View,
} from 'react-native';
import { styles } from './styles';
import BottomSheetKeyboardAwareScrollView from '../../../../components/BottomSheetKeyboardAwareScrollView';
import { keyboardExtraSpace, keyboardOffset } from '../../../../global/styles';
import { useAppTranslation } from '../../../../hooks/useAppTranslation';
import { Button, Input } from 'tradewize-component';
import { rating, unrating } from '../../../../assets/images';
import colors from '../../../../theme/colors';
import { useSafeAreaInsets } from 'react-native-safe-area-context';
import { logger } from '../../../../utils';
import { useDispatch, useSelector } from 'react-redux';

export interface BottomSheetRef {
  open: () => void;
  close: () => void;
}

export interface BottomSheetProps {
  userId: string;
  searchText: string;
}

const RenderStars = ({
  ratingValue,
  setRatingValue,
  isLoading,
}: {
  ratingValue: number;
  isLoading: boolean;
  setRatingValue: (value: number) => void;
}) => {
  return (
    <View style={styles.starsContainer}>
      {[1, 2, 3, 4, 5].map(star => (
        <Button
          disabled={isLoading}
          key={star}
          variant="ghost"
          style={styles.starButton}
          onPress={() => setRatingValue(star)}
        >
          <Image
            source={ratingValue >= star ? rating : unrating}
            style={styles.starImage}
          />
        </Button>
      ))}
    </View>
  );
};

const InputReview = forwardRef<BottomSheetRef, BottomSheetProps>(
  (props, ref) => {
    const { t } = useAppTranslation();
    const dispatch = useDispatch();

    const bottomSheetRef = useRef<BottomSheet>(null);
    const snapPoints = useMemo(() => ['45%', '80%'], []);
    const insets = useSafeAreaInsets();
    const [ratingValue, setRatingValue] = useState(0);
    const [reviewText, setReviewText] = useState<string>('');

    const isLoading = useSelector(
      (state: any) => state.network.reviews.isLoading,
    );

    useImperativeHandle(ref, () => ({
      open: () => {
        bottomSheetRef?.current?.snapToIndex(0);
      },
      close: () => {
        bottomSheetRef?.current?.close();
      },
    }));

    const handleSubmit = async () => {
      try {
        const redux = await import('auth/redux');
        if (ratingValue === 0) {
          dispatch(
            redux.actionContainer.showAlertAsync({
              title: t('WARNING'),
              message: t('PLEASE_SELECT_RATING'),
              type: 'warning',
              buttonText: t('OK'),
            }),
          );
          return;
        }
        dispatch(
          redux.actionContainer.createReviewAsync({
            userId: props.userId || '',
            rating: ratingValue,
            comments: reviewText,
            searchText: props?.searchText || '',
            refBottomSheetClose: () => {
              bottomSheetRef?.current?.close();
              setRatingValue(0);
              setReviewText('');
            },
          }),
        );
      } catch (error) {
        logger('error handleSubmit', error);
      }
    };

    return (
      <BottomSheet
        ref={bottomSheetRef}
        index={-1}
        animateOnMount={true}
        enableContentPanningGesture={false}
        enableHandlePanningGesture={true}
        enablePanDownToClose={false}
        enableDynamicSizing={false}
        keyboardBehavior="interactive"
        keyboardBlurBehavior="restore"
        snapPoints={snapPoints}
        style={styles.container}
        bottomInset={insets.bottom}
        // eslint-disable-next-line react/no-unstable-nested-components
        handleComponent={() => <View />}
        // eslint-disable-next-line react/no-unstable-nested-components, @typescript-eslint/no-shadow
        backdropComponent={(props: BottomSheetBackdropProps) => (
          <BottomSheetBackdrop
            {...props}
            opacity={0.5}
            appearsOnIndex={0}
            disappearsOnIndex={-1}
            pressBehavior="close"
            onPress={() => {
              Keyboard.dismiss();
              setTimeout(() => {
                bottomSheetRef?.current?.close();
              }, 150);
            }}
          />
        )}
      >
        <BottomSheetKeyboardAwareScrollView
          scrollEnabled={false}
          bottomOffset={keyboardOffset}
          extraKeyboardSpace={keyboardExtraSpace}
        >
          <TouchableNativeFeedback
            onPress={() => {
              Keyboard.dismiss();
            }}
          >
            <View style={styles.contentContainer}>
              <Text style={styles.titleReview}>{t('GIVE_A_REVIEW')}</Text>

              <RenderStars
                isLoading={isLoading}
                ratingValue={ratingValue}
                setRatingValue={setRatingValue}
              />

              <View style={styles.detailReviewContainer}>
                <Text style={styles.label}>{t('DETAIL_REVIEW')}</Text>
                <Input
                  editable={!isLoading}
                  inputContainerStyle={styles.inputContainer}
                  inputStyle={styles.input}
                  placeholder={t('ENTER_YOUR_REVIEW_HERE')}
                  multiline={true}
                  value={reviewText}
                  onChangeText={setReviewText}
                  onFocus={() => {
                    bottomSheetRef?.current?.snapToIndex(1);
                  }}
                  onBlur={() => {
                    bottomSheetRef?.current?.snapToIndex(0);
                  }}
                  borderColorActive={colors.mainColorPrimary}
                  cursorColor={colors.mainColorPrimary}
                  selectionColor={colors.mainColorPrimary}
                />
              </View>
              <Button
                isLoading={isLoading}
                disabled={isLoading}
                onPress={handleSubmit}
                variant="primary"
                style={styles.submitButton}
                title={t('SUBMIT')}
                textStyle={styles.submitButtonText}
              />
            </View>
          </TouchableNativeFeedback>
        </BottomSheetKeyboardAwareScrollView>
      </BottomSheet>
    );
  },
);

export default InputReview;
